var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…버려진 함선 치고 내부는 생각보다 깨끗하네.","JPN":"……捨てられた艦船にしては、中はずいぶん綺麗じゃん。","ENG":"…Not bad for an abandoned ship. It's cleaner than I expected.","TWN":"…雖然是廢棄的艦船，但內部比想像中乾淨。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"도깨비 같은 게 튀어나오는 건 아니겠지?","JPN":"お化けとか出てきたりしないよね？","ENG":"Hope nothing ghostly like a demon jumps out at us.","TWN":"不會有鬼怪跳出來吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"신호는 안쪽에서 잡히고 있어.","JPN":"信号は中のほうから出ている。","ENG":"The signal's coming from deeper inside.","TWN":"訊號在裡面。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…같이 가!","JPN":"……待って！","ENG":"…Wait up!","TWN":"…一起走！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"데이터 뱅크 찾았어. 생각보다 찾기 쉬운데? 암호화도 안되어 있고.","JPN":"データバンク、あったよ。思ったより簡単だったね。暗号化もされてないし。","ENG":"Found the data bank. That was easier than I thought. It's not even encrypted.","TWN":"找到資料庫了。比想像中好找？也沒有加密。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼 임무 완수군. 가지고 돌아가면 될 거다.","JPN":"じゃあ任務完了だな。それを持ち帰ればいいはずだ。","ENG":"Then mission accomplished. Let's bring it back.","TWN":"那任務就完成了。帶回去就行。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭘 관측하는 장치인가 했더니, 침식파 탐지 기록이 담겨있었구나.","JPN":"何を観測する装置かと思ったら、侵食波探知記録が保存されてる。","ENG":"Thought it was some kind of observatory device, but it's full of Corruption ray scan logs.","TWN":"我還以為是什麼觀測裝置，結果裡面裝的是侵蝕波探測紀錄。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의뢰인이 부탁한 걸 왜 멋대로 읽고 있지?","JPN":"依頼人に頼まれたものを、なぜ勝手に読んでいる？","ENG":"Why are you reading it? That wasn't part of the job.","TWN":"為什麼擅自讀委託人的東西？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"왜? 의뢰에 기록을 읽으면 안된다는 조항이라도 있었어?","JPN":"何？　依頼に、記録を読んじゃだめという条項があったの？","ENG":"Why not? Was there a clause saying we're not allowed to read the records during a job?","TWN":"怎麼？委託有規定不能讀取紀錄嗎？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…아니.","JPN":"……いや。","ENG":"…No.","TWN":"…沒有。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"뭐라고 쓰여있는데?","JPN":"何と書かれている？","ENG":"So, what does it say?","TWN":"上面寫了什麼？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"여기서 뭔가를 추적하고 있었나 봐. 우물이라 명명된 특정 좌표에서… 엄청 오랫동안.","JPN":"ここで何かを追跡してたみたい。「井戸」と命名された特定の座標で……すごく長い間。","ENG":"Looks like they were tracking something. In fixed coordinates marked as the Well… for a very long time.","TWN":"他們好像在這裡追蹤什麼。在一個被命名為井的特定座標…追蹤了很久。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"근데 추적하고 있던 게 평범한 침식체는 아닌 것 같아.","JPN":"でも、追跡していたのは普通の侵食体じゃないみたい。","ENG":"And whatever they were tracking wasn't an ordinary C.O.","TWN":"但追蹤的好像不是普通的侵蝕體。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이상침식파 시그니처 감지… 식별 타입은…","JPN":"異常侵食波シグネチャー感知……識別タイプは……","ENG":"Abnormal Corruption ray signature detected… classification type…","TWN":"偵測到異常侵蝕波訊號…識別類型是…"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"심연 원종… 세 짐승의 범?","JPN":"深淵原種……3匹のケモノの、虎？","ENG":"Primal Abyssal… Tiger of the Three Beasts?","TWN":"深淵原種…三隻野獸的虎？"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"위험한 녀석인가?","JPN":"危険なやつなのか？","ENG":"Is it dangerous?","TWN":"是個危險的傢伙嗎？"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"나도 모르겠어. 오피셜 리스트에도 없고.","JPN":"私にも分からない。オフィシャルリストに載ってないし。","ENG":"Beats me. Doesn't show up on any official lists.","TWN":"我也不知道。官方名單上沒有。"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국이 공개한 적 없는 이레귤러라면… 제법 위험한 녀석일지도?","JPN":"管理局が公開してないイレギュラーってことは……結構ヤバいやつかも？","ENG":"If it's an Irregular the Administration never disclosed… It could be real bad.","TWN":"如果這是管理局從未公開過的異類…那可能很危險。"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 함교의 데이터베이스를 뒤져보면 이 시그니처에 대한 정보를 얻을 수 있지 않을까?","JPN":"この艦橋のデータベースを漁ってみたら、このシグネチャーに関する情報が手に入るんじゃないかな？","ENG":"Maybe we'll find more on the signature if we dig into the bridge's database.","TWN":"如果查一下這艘艦橋的資料庫，是不是就能得到關於這個訊號的情報？"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"거기까지만 하지. 이런 일에 너무 깊이 관여하면 좋은 꼴을 못 볼…","JPN":"そこまでにしろ。こんなことに深入りすると、いい目を見な……","ENG":"Let's stop here. Get too deep in this kind of thing and it never ends well–","TWN":"到此為止吧。過度涉入這種事，不會有好下場的…"},"stage":{"bg":"MAINSTREAM_000002","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"너, 내 말을 듣고 있긴 한 거냐?","JPN":"お前、話聞いているのか？","ENG":"Hey, are you even listening to me?","TWN":"你到底有沒有在聽我說話？"},"stage":{"bg":"MAINSTREAM_000003","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국 데이터에 접근해볼 기회가 자주 있는 일은 아니잖아.","JPN":"管理局のデータベースにアクセスできる機会なんてめったにないんだよ。","ENG":"Come on, chances to access Administration data don't come every day.","TWN":"不是經常有機會能進入管理局的資料庫的。"},"stage":{"bg":"MAINSTREAM_000003","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"어르신은 궁금한 거 없어?","JPN":"おばあさんは知りたいこととかないの？","ENG":"Aren't you curious at all, granny?","TWN":"阿姨你沒有什麼好奇的嗎？"},"stage":{"bg":"MAINSTREAM_000003","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혹시 내 이름에 관한…","JPN":"もしかして私の名前に関する……","ENG":"Is there anything about my name…?","TWN":"比如說我的名字…"},"stage":{"bg":"MAINSTREAM_000003","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}}]`);export{e as default};